ValidationRule.errorConditionFormula:
AND( /* Run only when GST number is entered */ NOT(ISBLANK(DRC_NBC_GST_Number__c)),
/* Run only when BillingCountryCode is 'IN' */ TEXT(BillingCountryCode) = "IN",
/* Check either State Code mismatch or PAN mismatch */ OR( /* State Code Mismatch */ NOT( CASE( TEXT(BillingStateCode), "KA", "29", "MH", "27", "DL", "07", "GJ", "24", "TN", "33", "WB", "19", "UP", "09", "RJ", "08", "PB", "03", "KL", "32", "MP", "23", "HR", "06", "HP", "02", "JH", "20", "OD", "21", "CG", "22", "AS", "18", "AP", "37", "TS", "36", "BR", "10", "GA", "30", "AR", "12", "" /* default if no match */ ) = LEFT(DRC_NBC_GST_Number__c, 2) ),
/* PAN Number Mismatch (case-insensitive and trimmed) */ UPPER(TRIM(MID(DRC_NBC_GST_Number__c, 3, 10))) <> UPPER(TRIM(DRC_NBC_PAN_No__c)) ) )
